mapper.select:
SELECT B.BOARD_NO, B.BOARD_TITLE, B.WRITER_COMPANY, B.BOARD_WRITE_DATE, B.BOARD_VIEW_COUNT, B.BOARD_CATEGORY, I.BOARD_IMG_PATH, I.BOARD_IMG_RE FROM "BOARD" B LEFT JOIN "BOARD_IMAGE" I ON (I.BOARD_NO = B.BOARD_NO AND I.BOARD_IMG_ORDER = 0) WHERE B.BOARD_DEL_FL = 'N' AND B.BOARD_TYPE_CODE = #{boardTypeCode}
ORDER BY B.BOARD_VIEW_COUNT DESC, B.BOARD_NO DESC
ORDER BY B.BOARD_WRITE_DATE DESC, B.BOARD_NO DESC
